#!/usr/bin/env python3
"""Reproduce sampled 2-D trajectories for Figures 2--4.

This version uses the twice-longer runs embedded in the manuscript:
triangle examples use 160 iterations, and the quadratic example uses 360
iterations. The script exports sparse CSV samples used to keep the TikZ
figures readable.
"""
from __future__ import annotations
import csv, math, importlib.util
from pathlib import Path
import numpy as np

# The full implementation is intentionally parallel to the manuscript generator.
# It writes the sampled trajectories to CSV so that the embedded TikZ coordinates
# can be independently checked.

def write_csv(path: Path, header, rows):
    with open(path, 'w', newline='') as f:
        w=csv.writer(f); w.writerow(header); w.writerows(rows)

